pub fn rrf_merge(
    vector_results: &[(String, f32)],
    bm25_results: &[(String, f32)],
    ppr_results: &[(String, f32)],
    vector_weight: f32,
    bm25_weight: f32,
    ppr_weight: f32,
    limit: usize,
) -> Vec<(String, RrfScores)> {
    let mut scores: HashMap<String, RrfScores> = HashMap::new();

    for (rank, (id, original_score)) in vector_results.iter().enumerate() {
        let rrf_score = vector_weight / (RRF_K + rank as f32 + 1.0);
        let entry = scores.entry(id.clone()).or_default();
        entry.vector_score = *original_score;
        entry.combined_score += rrf_score;
    }

    for (rank, (id, original_score)) in bm25_results.iter().enumerate() {
        let rrf_score = bm25_weight / (RRF_K + rank as f32 + 1.0);
        let entry = scores.entry(id.clone()).or_default();
        entry.bm25_score = *original_score;
        entry.combined_score += rrf_score;
    }

    for (rank, (id, original_score)) in ppr_results.iter().enumerate() {
        let rrf_score = ppr_weight / (RRF_K + rank as f32 + 1.0);
        let entry = scores.entry(id.clone()).or_default();
        entry.ppr_score = *original_score;
        entry.combined_score += rrf_score;
    }

    let mut results: Vec<_> = scores.into_iter().collect();
    results.sort_by(|a, b| {
        b.1.combined_score
            .partial_cmp(&a.1.combined_score)
            .unwrap_or(std::cmp::Ordering::Equal)
    });
    results.truncate(limit);
    results
}

pub fn personalized_page_rank(
    graph: &DiGraph<String, f32>,
    seed_nodes: &[NodeIndex],
    damping: f32,
    tolerance: f32,
    max_iter: usize,
) -> HashMap<NodeIndex, f32> {
    let n = graph.node_count();
    if n == 0 {
        return HashMap::new();
    }

    let mut personalization = vec![0.0; n];
    if !seed_nodes.is_empty() {
        let seed_weight = 1.0 / seed_nodes.len() as f32;
        for &node in seed_nodes {
            if node.index() < n {
                personalization[node.index()] = seed_weight;
            }
        }
    } else {
        let uniform = 1.0 / n as f32;
        personalization.fill(uniform);
    }

    let mut scores = personalization.clone();

    let out_weight_sums: Vec<f32> = graph
        .node_indices()
        .map(|node| graph.edges(node).map(|e| *e.weight()).sum::<f32>())
        .collect();

    let dangling_nodes: Vec<NodeIndex> = graph
        .node_indices()
        .filter(|&node| out_weight_sums[node.index()] == 0.0)
        .collect();

    for _ in 0..max_iter {
        let mut new_scores = vec![0.0; n];

        let dangling_sum: f32 = dangling_nodes
            .iter()
            .map(|&node| scores[node.index()])
            .sum();

        for node in graph.node_indices() {
            let total_out_weight = out_weight_sums[node.index()];
            if total_out_weight > 0.0 {
                for edge in graph.edges(node) {
                    let weight = *edge.weight();
                    let transition_prob = weight / total_out_weight;
                    let contribution = scores[node.index()] * transition_prob * damping;
                    new_scores[edge.target().index()] += contribution;
                }
            }
        }

        for i in 0..n {
            new_scores[i] += damping * dangling_sum * personalization[i];
            new_scores[i] += (1.0 - damping) * personalization[i];
        }

        let diff: f32 = scores
            .iter()
            .zip(new_scores.iter())
            .map(|(a, b)| (a - b).abs())
            .sum();

        scores = new_scores;

        if diff < tolerance {
            break;
        }
    }

    graph
        .node_indices()
        .map(|idx| (idx, scores[idx.index()]))
        .collect()
}

