                embedding_enqueue_elapsed_ms,
                relation_create_elapsed_ms,
                status_update_elapsed_ms,
                chunks_written,
                symbols_written,
                embeddings_enqueued,
                files_read,
                files,
            )
            .await
        }
        CodeIndexPipelineMode::Staged => {
            run_staged_index_pipeline(
