pub(crate) async fn search_code_with_context(
    state: &Arc<AppState>,
    params: SearchCodeParams,
    context: Option<CodeToolContext>,
) -> anyhow::Result<CallToolResult> {
    crate::ensure_embedding_ready!(state);

    let SearchCodeParams {
        query,
        project_id,
        limit,
    } = params;
    let project_resolution =
        resolve_project_for_code_tool(state, normalize_project_id(project_id), context.as_ref())
            .await;
    let project_id = project_resolution.project_id().map(str::to_string);

    let mut is_partial = false;
    let mut indexing_message = None;

    let mut project_status = None;
    if let Some(ref project_id) = project_id {
        if let Ok(Some(status)) = state.storage.get_index_status(project_id).await {
            if status.status == crate::types::IndexState::Indexing
                || status.status == crate::types::IndexState::EmbeddingPending
            {
                is_partial = true;
                indexing_message = Some(format!(
                    "Indexing in progress ({}/{} files). Results may be incomplete.",
                    status.indexed_files, status.total_files
                ));
            }
            project_status = Some(status);
        }
    }

    let limit = normalize_limit(limit);

    if project_resolution.is_stale_binding() {
        let mut response = json!({
            "results": [],
            "count": 0,
            "summary": summary_collection_response(
                "collection",
                0,
                Some(0),
                true,
                Some("Session-bound project is stale; refusing cross-project fallback.".to_string()),
            ),
            "query": query,
            "contract": code_search_contract_json(project_id.as_deref(), project_status.as_ref()),
            "vector_hits": 0,
            "bm25_hits": 0,
            "is_partial": true,
            "message": "Session-bound project is stale; refusing cross-project fallback."
        });
        apply_project_resolution(&mut response, &project_resolution);
        return Ok(success_json(response));
    }

    let query_embedding = state.embedding.embed(&query).await?;

    // Run vector search and BM25 in parallel for robust results.
    // Previously BM25 was only a fallback — degenerate vectors masked BM25 entirely.
    let project_id = project_id.as_deref();
    let (vector_results, bm25_results) = tokio::join!(
        async {
            match state
                .storage
                .vector_search_code(&query_embedding, project_id, limit)
                .await
            {
                Ok(results) => {
                    tracing::debug!(hits = results.len(), "search_code: vector search completed");
                    results
                }
                Err(e) => {
                    tracing::warn!(error = %e, "search_code: vector search failed, falling back to empty");
                    Vec::new()
                }
            }
        },
        async {
            state
                .code_search
                .search(&query, project_id, limit, state.storage.as_ref())
                .await
        }
    );

    // Merge: vector results first, then BM25 results not already present.
    // This gives vector priority in ranking while ensuring BM25 fills gaps.
    use std::collections::HashSet;
    let mut seen_ids: HashSet<String> = HashSet::new();
    let mut merged = Vec::with_capacity(limit);

    for r in &vector_results {
        if seen_ids.insert(r.id.clone()) {
            merged.push(json!({
                "id": r.id,
                "file_path": r.file_path,
                "content": r.content,
                "language": r.language,
                "start_line": r.start_line,
                "end_line": r.end_line,
                "chunk_type": r.chunk_type,
                "name": r.name,
                "context_path": r.context_path,
                "score": r.score,
                "source": "vector"
            }));
        }
        if merged.len() >= limit {
            break;
        }
    }

    for r in &bm25_results {
        if merged.len() >= limit {
            break;
        }
        if seen_ids.insert(r.id.clone()) {
            merged.push(json!({
                "id": r.id,
                "file_path": r.file_path,
                "content": r.content,
                "language": r.language,
                "start_line": r.start_line,
                "end_line": r.end_line,
                "chunk_type": r.chunk_type,
                "name": r.name,
                "context_path": r.context_path,
                "score": r.score,
                "source": "bm25"
            }));
        }
    }

    let missing_project_diagnostic =
        super::missing_project_binding_diagnostic(state, project_id).await;

    let mut response = json!({
        "results": merged,
        "count": merged.len(),
        "summary": summary_collection_response(
            "collection",
            merged.len(),
            Some(merged.len()),
            is_partial,
            indexing_message.clone(),

                let lifecycle = match binding.project_id.as_deref() {
                    Some(project_id) => binding_lifecycle_response(
                        self.state
                            .storage
                            .get_index_status(project_id)
                            .await
                            .ok()
                            .flatten()
                            .as_ref(),
                    ),
                    None => json!({
                        "summary": {
                            "result_kind": "binding_status",
                            "partial": {
                                "is_partial": false,
                                "reason_code": "ok",
                                "reason": "unbound",
                                "message": "No project is currently bound for this session."
                            }
                        }
                    }),
                };

                Ok(logic::success_json(json!({
                    "action": "binding_status",
                    "binding": binding_response(&binding),
                    "lifecycle": lifecycle,
                })))
            }
            other => Err(ErrorData {
                code: ErrorCode(-32602),
                message: format!("Invalid action '{}'. Use: list, index, status, stats, projection, projection_by_locator, bind, unbind, binding_status", other).into(),
                data: None,
            }),
        }
    }

