fn lifecycle_view_from_status(status: &crate::types::IndexStatus) -> crate::types::LifecycleView {
    crate::types::LifecycleView {
        structural: crate::types::StructuralLifecycleView {
            state: status.structural_state.to_string(),
            is_ready: status.structural_state == crate::types::StructuralState::Ready,
            generation: status.structural_generation,
        },
        semantic: crate::types::SemanticLifecycleView {
            state: status.semantic_state.to_string(),
            is_ready: status.semantic_state == crate::types::SemanticState::Ready,
            generation: status.semantic_generation,
            is_caught_up: status.semantic_state == crate::types::SemanticState::Ready
                && status.semantic_generation == status.structural_generation,
        },
        projection: crate::types::ProjectionLifecycleView {
            state: status.projection_state.to_string(),
            is_current: status.projection_state == crate::types::ProjectionState::Current,
        },
    }
}

async fn rebuild_bm25_and_finalize_index_status(
    state: &Arc<AppState>,
    project_id: &str,
    status: IndexStatus,
    active_structural_generation: u64,
) -> Result<IndexStatus> {
    ensure_index_generation_current(state, project_id, active_structural_generation).await?;

    match state
        .code_search
        .try_rebuild_from_storage(state.storage.as_ref(), project_id)
        .await
    {
        Ok(_) => finalize_index_status_if_current(state, status, active_structural_generation).await,
        Err(error) => Err(record_bm25_rebuild_failure_if_current(
            state,
            project_id,
            status,
            active_structural_generation,
            error,
        )
        .await),
    }
}

fn tool_context_session_identity() {
        let extensions = extensions_with_request_headers(&[(MCP_SESSION_ID_HEADER, "session-abc")]);

        assert_eq!(
            extract_session_id_from_extensions(&extensions).as_deref(),
            Some("session-abc")
        );
    }

async fn index_project_emits_baseline_timing_events_for_fixture() {
        let captured_phases = init_timing_phase_capture();
        let ctx = TestContext::new().await;
        let project_dir = ctx._temp_dir.path().join("phase-checkpoints-project");
        fs::create_dir_all(&project_dir).unwrap();
        fs::write(
            project_dir.join("lib.rs"),
            "pub fn alpha() -> i32 { beta() }\nfn beta() -> i32 { 1 }\n",
        )
        .unwrap();

        let status = index_project(ctx.state.clone(), &project_dir)
            .await
            .unwrap();

        assert_eq!(status.status, IndexState::EmbeddingPending);
        assert_eq!(status.total_files, 1);
        assert!(status.total_chunks >= 1);
        assert!(status.total_symbols >= 2);

        let phases = captured_phases.lock().unwrap().clone();
        for required_phase in [
            "cleanup",
            "scan",
            "file_read_hash",
            "parse_chunk",
            "chunk_db_write",
            "symbol_db_write",
            "embedding_enqueue",
            "status_update",
            "bm25_rebuild",
            "total_index",
        ] {
            eprintln!("captured_timing_phase={required_phase}");
            assert!(
                phases.iter().any(|phase| phase == required_phase),
                "missing timing phase {required_phase}; captured phases: {phases:?}"
            );
        }
    }

